// src/views/user/MyProfile/composables/useModules.js
import { ref, computed } from 'vue'
import { showToast } from '@/components/ToastMessage'
import { user } from '@/api/user'
import { profile } from '@/api/profile'

export function useModules() {
  const loading = ref(false)
  const activeModules = ref([])
  const inactiveModules = ref([])

  // 获取布局和模块数据
  const fetchModulesData = async () => {
    try {
      loading.value = true

      // 1. 获取布局配置
      const layoutResponse = await user.getProfileLayout()
      if (layoutResponse.data?.code === 200) {
        const layout = layoutResponse.data.data

        // 2. 获取各模块的数据
        const [jobIntentionRes, workExperienceRes] = await Promise.all([
          profile.jobIntention.get(),
          profile.workExperience.list()
        ])

        // 3. 整合数据
        const modules = []

        // 求职意向模块
        if (layout.job_intention?.visible) {
          modules.push({
            type: 'job_intention',
            name: '求职意向',
            order: layout.job_intention.order,
            visible: true,
            data: jobIntentionRes.data?.code === 200 ? jobIntentionRes.data.data : null
          })
        }

        // 工作经历模块
        if (layout.work_experience?.visible) {
          modules.push({
            type: 'work_experience',
            name: '工作经历',
            order: layout.work_experience.order,
            visible: true,
            data: workExperienceRes.data?.code === 200 ? workExperienceRes.data.data : null
          })
        }

        // 更新状态
        activeModules.value = modules.sort((a, b) => a.order - b.order)

        // 未激活的模块
        inactiveModules.value = Object.entries(layout)
          .filter(([key, config]) => !config.visible && key !== 'basic_info')
          .map(([key, config]) => ({
            type: key,
            name: getModuleName(key),
            order: config.order,
            visible: false,
            data: null
          }))
          .sort((a, b) => a.order - b.order)
      }
    } catch (error) {
      console.error('获取模块数据失败:', error)
      showToast('获取模块数据失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 添加模块
  const addModule = async (moduleType) => {
    try {
      loading.value = true

      // 1. 更新布局
      const layout = activeModules.value.reduce((acc, m) => {
        acc[m.type] = { order: m.order, visible: true }
        return acc
      }, {})

      // 添加新模块
      layout[moduleType] = { 
        order: activeModules.value.length + 1, 
        visible: true 
      }

      const response = await user.updateProfileLayout({ layout })

      if (response.data?.code === 200) {
        // 2. 重新获取所有数据
        await fetchModulesData()
        showToast('模块已添加', 'success')
      }
    } catch (error) {
      console.error('添加模块失败:', error)
      showToast('添加模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 移除模块
  const removeModule = async (moduleType) => {
    try {
      loading.value = true

      // 1. 更新布局
      const layout = activeModules.value.reduce((acc, m) => {
        if (m.type === moduleType) {
          acc[m.type] = { order: m.order, visible: false }
        } else {
          acc[m.type] = { order: m.order, visible: true }
        }
        return acc
      }, {})

      const response = await user.updateProfileLayout({ layout })

      if (response.data?.code === 200) {
        // 2. 重新获取所有数据
        await fetchModulesData()
        showToast('模块已移除', 'success')
      }
    } catch (error) {
      console.error('移除模块失败:', error)
      showToast('移除模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    activeModules,
    inactiveModules,
    fetchModulesData,
    addModule,
    removeModule
  }
}
